const now = new Date();
const d = new Date(now); d.setDate(now.getDate() + 2);
const fmt = x => parseInt(`${x.getFullYear()}${String(x.getMonth()+1).padStart(2,'0')}${String(x.getDate()).padStart(2,'0')}`);
return [{ json: { fechaObj: fmt(d) } }];

const i = $input.item.json;
const h = i.Hora||0, hh=String(Math.floor(h/100)).padStart(2,'0'), mm=String(h%100).padStart(2,'0');
const msg = `👶 Hola, recordamos la cita de *${i.nombre_menor}* en ${$vars.CLINICA_NOMBRE}.

📅 Pasado mañana a las *${hh}:${mm}h*

Explícale que es solo una revisión para que venga tranquilo/a 😊

Responde *SÍ* para confirmar o llámanos si necesitas cambiarla: ${$vars.CLINICA_TELEFONO}`;
return [{ json: { ...i, mensaje: msg } }];
